window.__DATA_CACHE__.TAROT_78 = {"majorArcana": [{"number": 0, "name": "愚者", "english": "The Fool", "symbol": "🃏", "upright": "新的开始、天真、自由、冒险、信仰的飞跃", "reversed": "鲁莽、冒险、缺乏方向、冲动", "reading_upright": "愚者牌代表一段全新旅程的开始。你正站在人生的十字路口，虽然前方充满未知，但你的内心充满了勇气和期待。放下过去的包袱，以纯真的心态去迎接新的挑战。这张牌鼓励你相信直觉，大胆踏出第一步。", "reading_reversed": "你可能在过于冲动地行动，没有充分考虑后果。或者你虽然想要改变，却被恐惧所束缚，不敢迈出那一步。", "keywords": ["新开始", "冒险", "天真", "自由", "信仰"]}, {"number": 1, "name": "魔术师", "english": "The Magician", "symbol": "🎩", "upright": "创造力、技能、意志力、显化、资源丰富", "reversed": "操纵、欺骗、缺乏计划、能力未发挥", "reading_upright": "魔术师告诉你，你已经拥有实现目标所需的一切资源和能力。天地之间的能量汇聚在你身上，现在是行动的最佳时机。将你的想法转化为现实，你的意志力和创造力将达到顶峰。", "reading_reversed": "你可能正在浪费自己的才华，或者有人在用花言巧语蒙蔽你。审视一下自己是否真正在运用自己的能力。", "keywords": ["创造", "技能", "意志", "显化", "资源"]}, {"number": 2, "name": "女祭司", "english": "The High Priestess", "symbol": "🌙", "upright": "直觉、神秘、潜意识、内在智慧、安静的力量", "reversed": "秘密、表面化、忽视直觉、内心混乱", "reading_upright": "女祭司提醒你倾听内心的声音。答案并不在外部世界中，而是深藏于你的潜意识之中。保持安静和内省，你的直觉将引导你找到真相。有些事情现在不需要急着行动，静静观察和等待即可。", "reading_reversed": "你可能忽视了自己内心的声音，过于依赖外界的意见。或者有些秘密正在浮出水面，让你感到不安。", "keywords": ["直觉", "神秘", "内在智慧", "安静", "潜意识"]}, {"number": 3, "name": "女皇", "english": "The Empress", "symbol": "👑", "upright": "丰饶、母性、自然、创造力、感官享受", "reversed": "依赖、过度保护、创造力受阻、忽视自我", "reading_upright": "女皇代表生命的丰盛和创造力的涌流。这是一个充满爱与美的时期，你与自然和感官世界有着深刻的连接。无论是在事业、感情还是个人成长上，你都将收获丰硕的果实。", "reading_reversed": "你可能过度依赖他人或沉溺于物质享受中。或者你的创造力受到了压抑，需要重新找回内心的丰饶。", "keywords": ["丰饶", "创造", "母性", "自然", "美"]}, {"number": 4, "name": "皇帝", "english": "The Emperor", "symbol": "🏛️", "upright": "权威、结构、控制、领导力、稳定", "reversed": "专制、僵化、控制欲过强、缺乏纪律", "reading_upright": "皇帝牌代表秩序和权威。你需要建立清晰的结构和规则来管理你的生活或事业。展现你的领导力，以理性和决断来掌控局面。稳定和纪律将是你成功的基础。", "reading_reversed": "你可能过于控制或者被他人的权威所压制。灵活一些，不要让规则成为束缚。", "keywords": ["权威", "领导", "结构", "稳定", "纪律"]}, {"number": 5, "name": "教皇", "english": "The Hierophant", "symbol": "⛪", "upright": "传统、信仰、教育、指导、精神追求", "reversed": "打破常规、反叛、自由思考、非传统", "reading_upright": "教皇代表精神和智慧的传承。你可能需要一个导师或指引者来帮助你成长。遵循传统的智慧，或者考虑接受系统的教育和训练。信仰和价值观将是你做决定的基石。", "reading_reversed": "你可能正在质疑既有的规则和传统，想要走一条属于自己的路。这并非坏事，但要确保你的反叛有充分的理由。", "keywords": ["传统", "信仰", "指导", "精神", "智慧"]}, {"number": 6, "name": "恋人", "english": "The Lovers", "symbol": "💕", "upright": "爱情、和谐、关系、价值观选择、深度连接", "reversed": "失衡、不和谐、价值观冲突、不当的关系", "reading_upright": "恋人牌不仅代表爱情，更代表人生中重要的选择。你可能面临一个需要听从内心的重要决定。如果你在感情方面提问，这张牌预示着一段深刻的情感连接即将到来或正在加深。", "reading_reversed": "你的关系可能面临一些挑战，或者你在重要的选择上感到犹豫不决。理清自己的价值观，做出符合内心的选择。", "keywords": ["爱情", "选择", "和谐", "连接", "价值观"]}, {"number": 7, "name": "战车", "english": "The Chariot", "symbol": "⚡", "upright": "胜利、意志力、决心、控制、征服", "reversed": "失去方向、自控力不足、挫败、内心冲突", "reading_upright": "战车牌代表通过坚强的意志力取得胜利。你正驾驭着两股看似对立的力量，但凭借你的决心和控制力，你将克服一切障碍。胜利就在前方，保持前进的动力！", "reading_reversed": "你可能感到失控或者内心充满矛盾。前行的道路上出现了阻碍，需要重新找到你的方向和动力。", "keywords": ["胜利", "意志", "决心", "控制", "前进"]}, {"number": 8, "name": "力量", "english": "Strength", "symbol": "🦁", "upright": "内在力量、勇气、耐心、柔克刚、自信", "reversed": "自我怀疑、软弱、缺乏勇气、内心脆弱", "reading_upright": "力量牌告诉你，真正的力量不在于蛮力，而在于内在的勇气和耐心。你正面对一个需要以柔克刚的挑战。用爱和慈悲来化解冲突，你的内在力量比你想象的要强大得多。", "reading_reversed": "你可能在自我怀疑中挣扎，感到内心的脆弱和不安。记住，承认自己的脆弱也是一种力量。", "keywords": ["勇气", "耐心", "内在力量", "柔克刚", "自信"]}, {"number": 9, "name": "隐士", "english": "The Hermit", "symbol": "🏔️", "upright": "内省、独处、智慧、指引、寻找真相", "reversed": "孤立、逃避、固执、拒绝帮助", "reading_upright": "隐士牌邀请你暂时离开喧嚣的世界，向内探索。独处不是孤独，而是一种珍贵的自我对话的机会。你需要安静下来，倾听内心深处的声音，寻找属于自己的真相和方向。", "reading_reversed": "你可能过于封闭自己，不愿意接受他人的帮助。适度独处是好的，但过度隔离会让你失去与世界的连接。", "keywords": ["内省", "独处", "智慧", "探索", "真相"]}, {"number": 10, "name": "命运之轮", "english": "Wheel of Fortune", "symbol": "🎡", "upright": "命运转折、机遇、循环、好运、改变", "reversed": "厄运、抗拒改变、失控、周期低谷", "reading_upright": "命运之轮告诉你，变化即将来临。命运的齿轮正在转动，一个新的周期即将开始。这是一个充满机遇的时刻，好运正在向你走来。拥抱变化，顺势而为。", "reading_reversed": "你可能正经历一段低谷期，感觉事情不太顺利。但请记住，命运之轮永远在转动，低谷之后必有高峰。", "keywords": ["命运", "转折", "机遇", "改变", "循环"]}, {"number": 11, "name": "正义", "english": "Justice", "symbol": "⚖️", "upright": "公正、真相、因果、责任、法律", "reversed": "不公正、逃避责任、偏见、不诚实", "reading_upright": "正义牌代表因果报应和公正的裁决。你过去的行为将得到应有的回报。如果你一直行事正直，那么公正的结果将站在你这边。面对真相，承担起你应尽的责任。", "reading_reversed": "你可能正在回避某些真相或责任。不公正的事情可能正在发生，需要你勇敢地站出来。", "keywords": ["公正", "真相", "因果", "责任", "公平"]}, {"number": 12, "name": "倒吊人", "english": "The Hanged Man", "symbol": "🙃", "upright": "暂停、新视角、牺牲、放手、等待", "reversed": "拖延、无意义的牺牲、抗拒、停滞", "reading_upright": "倒吊人告诉你，有时候停下来反而是一种前进。你现在需要的不是行动，而是从一个全新的角度来看待问题。放下执念，接受当前的处境，你会发现不一样的答案。", "reading_reversed": "你可能在一个无意义的牺牲中纠结太久，或者明明需要行动却一直在拖延。是时候做出改变了。", "keywords": ["暂停", "新视角", "放手", "等待", "领悟"]}, {"number": 13, "name": "死神", "english": "Death", "symbol": "🦋", "upright": "结束、转变、重生、放下过去、蜕变", "reversed": "抗拒改变、害怕结束、停滞、依恋过去", "reading_upright": "死神牌并不意味着真正的死亡，而是象征着一个旧阶段的结束和新阶段的开始。你正在经历一次深刻的蜕变，旧的必须消逝，新的才能诞生。勇敢地拥抱这个转变吧。", "reading_reversed": "你可能在抗拒一个不可避免的改变，紧紧抓住过去不放。放手虽然痛苦，但却是成长的必经之路。", "keywords": ["转变", "结束", "重生", "蜕变", "放下"]}, {"number": 14, "name": "节制", "english": "Temperance", "symbol": "☯", "upright": "平衡、和谐、耐心、适度、融合", "reversed": "失衡、过度、急躁、缺乏长远规划", "reading_upright": "节制牌代表平衡与和谐。你需要在生活中的各个方面找到适度的平衡点。不急不躁，循序渐进，将不同的元素融合成一个和谐的整体。耐心和节制将带你走向成功。", "reading_reversed": "你可能走极端了——要么太过，要么不及。或者在追求目标时过于急躁，缺乏耐心。需要重新找回平衡。", "keywords": ["平衡", "和谐", "耐心", "适度", "融合"]}, {"number": 15, "name": "恶魔", "english": "The Devil", "symbol": "⛓️", "upright": "束缚、诱惑、物质主义、阴影、执念", "reversed": "解脱、突破限制、觉醒、释放", "reading_upright": "恶魔牌揭示那些束缚你的东西——可能是物质的贪欲、不健康的关系、或者内心的恐惧和执念。这些锁链看起来很牢固，但仔细看，它们其实松松地挂着。你随时可以挣脱，关键在于你是否愿意面对自己的阴影。", "reading_reversed": "你正在从一个束缚中解脱出来。无论是成瘾、坏习惯还是有毒的关系，你正在重新获得自由。", "keywords": ["束缚", "诱惑", "阴影", "执念", "解脱"]}, {"number": 16, "name": "塔", "english": "The Tower", "symbol": "🗼", "upright": "突变、崩塌、觉醒、真相揭露、打破旧有", "reversed": "逃避灾难、恐惧改变、小波动、迟来的改变", "reading_upright": "塔牌代表突然的和剧烈的变化。一些建立在虚假基础上的事物即将崩塌。虽然这个过程可能很痛苦，但它将揭示真相，为你清除掉不再适合你的一切。灾后重建，你会发现一切比以前更好。", "reading_reversed": "你可能勉强避免了一场灾难，或者变化正在缓慢发生。不要心存侥幸，面对需要面对的问题。", "keywords": ["突变", "崩塌", "觉醒", "真相", "重建"]}, {"number": 17, "name": "星星", "english": "The Star", "symbol": "✨", "upright": "希望、灵感、宁静、治愈、精神指引", "reversed": "失去希望、悲观、信心不足、迷茫", "reading_upright": "经历风暴之后，星星终于出现了。这张牌带来希望和治愈的能量。你正处于一个灵感和创造力丰富的时期，宇宙正在向你传递积极的信号。保持乐观和开放，美好的事情即将到来。", "reading_reversed": "你可能感到迷茫和绝望，看不到前方的希望。但请相信，星星一直都在，只是暂时被云层遮挡了。", "keywords": ["希望", "灵感", "治愈", "宁静", "指引"]}, {"number": 18, "name": "月亮", "english": "The Moon", "symbol": "🌕", "upright": "幻觉、恐惧、潜意识、不确定性、直觉", "reversed": "走出迷雾、真相显现、克服恐惧、释放焦虑", "reading_upright": "月亮牌代表梦境与幻象之间的模糊地带。你正面对着不确定性和恐惧，事情并不像表面看起来那样。倾听你的直觉，但也要注意辨别幻象和真相。这是一个需要耐心和信任的时期。", "reading_reversed": "迷雾正在散去，真相开始浮出水面。你正在克服内心的恐惧和焦虑。", "keywords": ["幻觉", "恐惧", "直觉", "不确定", "潜意识"]}, {"number": 19, "name": "太阳", "english": "The Sun", "symbol": "☀️", "upright": "快乐、成功、活力、积极、光明", "reversed": "暂时的挫折、过度乐观、缺乏热情、延迟的成功", "reading_upright": "太阳牌是塔罗牌中最积极的牌之一！快乐、成功、活力——一切都在向着最好的方向发展。你的努力将得到丰厚的回报，享受这段阳光灿烂的时光吧！", "reading_reversed": "虽然暂遇挫折，但太阳依然在那里。保持乐观的心态，成功只是延迟，不会缺席。", "keywords": ["快乐", "成功", "活力", "光明", "积极"]}, {"number": 20, "name": "审判", "english": "Judgement", "symbol": "📯", "upright": "觉醒、重生、召唤、反思、第二次机会", "reversed": "自我怀疑、拒绝改变、无法释怀", "reading_upright": "审判牌代表一次深刻的觉醒和重生。你可能听到了内心深处的召唤，需要对自己的人生做出一个重要的评判和决定。过去的经历都在为这一刻做准备。接受这个召唤，迎接你的第二次机会。", "reading_reversed": "你可能在逃避一个需要做出的重要决定，或者无法原谅自己过去的错误。是时候放过自己了。", "keywords": ["觉醒", "重生", "召唤", "反思", "决定"]}, {"number": 21, "name": "世界", "english": "The World", "symbol": "🌍", "upright": "完成、圆满、成就、旅程的终点与起点", "reversed": "未完成、缺乏闭合、延迟的成就", "reading_upright": "世界牌代表一个完整循环的圆满结束。你已经完成了一段重要的旅程，取得了令人瞩目的成就。庆祝你的成功吧！同时记住，每一个结束也是一个新的开始，你的下一段精彩旅程即将启程。", "reading_reversed": "你可能感觉还有未完成的事情，缺少一种闭合感。不要着急，再给自己一些时间。", "keywords": ["圆满", "完成", "成就", "旅程", "新开始"]}], "minorArcana": {"wands": [{"name": "权杖Ace", "english": "Ace of Wands", "symbol": "🔥", "suit": "权杖", "number": "Ace", "upright": "创造力萌芽、灵感、新的热情、行动力", "reversed": "延迟、缺乏热情、方向不明确", "reading_upright": "一股新的能量和灵感正在涌入你的生活。这是一个充满激情和创造力的时刻，勇敢地抓住这个火花吧！", "reading_reversed": "你可能感到缺乏动力或热情，新的项目迟迟无法启动。找到激发你激情的事物。", "keywords": ["灵感", "热情", "开始", "能量", "创造"]}, {"name": "权杖二", "english": "Two of Wands", "symbol": "🏰", "suit": "权杖", "number": "2", "upright": "规划、未来愿景、决策、探索选择", "reversed": "害怕未知、缺乏规划、困在舒适区", "reading_upright": "你站在世界的边缘，眺望着远方。未来的可能性在你面前展开，现在是做好规划、做出选择的时候。", "reading_reversed": "你可能因为害怕未知而犹豫不决，困在当前的安全区域中。勇敢迈出去。", "keywords": ["规划", "选择", "愿景", "未来", "决定"]}, {"name": "权杖三", "english": "Three of Wands", "symbol": "⛵", "suit": "权杖", "number": "3", "upright": "扩展、远见、贸易、等待回报", "reversed": "延迟、障碍、缺乏远见", "reading_upright": "你的努力正在向外扩展，种子已经种下，现在需要耐心等待它们发芽。远方的回报正在向你走来。", "reading_reversed": "你可能因为一些障碍而感到沮丧，进展不如预期。坚持下去，收获只是需要更多时间。", "keywords": ["扩展", "远见", "等待", "进步", "贸易"]}, {"name": "权杖四", "english": "Four of Wands", "symbol": "🎉", "suit": "权杖", "number": "4", "upright": "庆祝、和谐、归属感、喜悦、稳定", "reversed": "不稳定、过渡期、缺乏支持", "reading_upright": "这是一个值得庆祝的时刻！无论是婚礼、毕业还是项目完成，快乐和和谐围绕着你。享受这个美好的时刻。", "reading_reversed": "你可能正处于一个不稳定的状态中，缺少安全感和归属感。寻找你的支持系统。", "keywords": ["庆祝", "和谐", "喜悦", "稳定", "归属"]}, {"name": "权杖五", "english": "Five of Wands", "symbol": "⚔️", "suit": "权杖", "number": "5", "upright": "竞争、冲突、多样性挑战、分歧", "reversed": "和解、避免冲突、合作", "reading_upright": "你正面对着竞争和分歧。不同的声音和意见在你周围碰撞。这不一定是坏事，竞争可以激发更好的表现。", "reading_reversed": "冲突正在缓解，各方开始寻找共同点。倾向于合作而非对抗。", "keywords": ["竞争", "冲突", "分歧", "挑战", "多样化"]}, {"name": "权杖六", "english": "Six of Wands", "symbol": "🏆", "suit": "权杖", "number": "6", "upright": "胜利、认可、骄傲、领导力", "reversed": "过度骄傲、失败、缺乏认可", "reading_upright": "你取得了令人瞩目的成就，赢得了他人的认可和赞赏。享受属于你的荣耀时刻，但保持谦逊。", "reading_reversed": "你可能过于在意他人的看法，或者因为某些挫折而感到失落。真正的价值不需要外界的认可。", "keywords": ["胜利", "认可", "骄傲", "成功", "领导"]}, {"name": "权杖七", "english": "Seven of Wands", "symbol": "🛡️", "suit": "权杖", "number": "7", "upright": "坚持立场、防御、勇气、挑战", "reversed": "放弃、承受不住压力、妥协", "reading_upright": "你正在为自己的信念而战。虽然面对着诸多挑战和质疑，但你的立场是坚定的。坚持到底，你将证明自己是对的。", "reading_reversed": "你可能正在考虑放弃，压力让你感到不堪重负。评估一下这个战斗是否值得继续。", "keywords": ["坚持", "防御", "勇气", "挑战", "立场"]}, {"name": "权杖八", "english": "Eight of Wands", "symbol": "💨", "suit": "权杖", "number": "8", "upright": "快速进展、变化、行动、速度", "reversed": "延迟、混乱、急于求成", "reading_upright": "事情正在快速发展！多件事情同时在推进，变化来得迅速而猛烈。抓住这股势头，顺势而为。", "reading_reversed": "你可能感到事情一团糟，进展不如预期那么快。放慢脚步，理清头绪。", "keywords": ["速度", "进展", "变化", "行动", "势头"]}, {"name": "权杖九", "english": "Nine of Wands", "symbol": "💪", "suit": "权杖", "number": "9", "upright": "韧性、坚持、最后的挑战、毅力", "reversed": "疲惫、放弃、防御过度", "reading_upright": "你已经经历了许多考验，虽然伤痕累累，但你依然站着。最后的挑战就在面前，坚持住，胜利即将到来。", "reading_reversed": "你可能已经精疲力竭，几乎想要放弃。允许自己休息一下，然后重新出发。", "keywords": ["韧性", "坚持", "毅力", "最后关头", "勇气"]}, {"name": "权杖十", "english": "Ten of Wands", "symbol": " burdens", "suit": "权杖", "number": "10", "upright": "负担、过劳、责任、压力", "reversed": "分担、放下、委托他人", "reading_upright": "你背负了太多的责任和负担。是时候学会说\"不\"了，把一些重担分摊出去。你不必独自承担一切。", "reading_reversed": "你开始学会放下一些负担，寻找帮助。这是一个积极的转变。", "keywords": ["负担", "过劳", "责任", "压力", "释放"]}], "cups": [{"name": "圣杯Ace", "english": "Ace of Cups", "symbol": "💧", "suit": "圣杯", "number": "Ace", "upright": "新的情感、爱、直觉、灵性觉醒", "reversed": "情感封闭、压抑感情、空虚", "reading_upright": "一颗充满爱和情感的种子正在你的心中萌芽。新的关系、新的情感体验、或者更深层的灵性意识正在到来。敞开你的心扉去接受这份礼物。", "reading_reversed": "你可能封闭了自己的情感，不愿意去感受或表达。打开心门，让爱流淌。", "keywords": ["爱", "情感", "直觉", "新的开始", "灵性"]}, {"name": "圣杯二", "english": "Two of Cups", "symbol": "🤝", "suit": "圣杯", "number": "2", "upright": "连接、伙伴关系、 mutual attraction、和谐", "reversed": "失衡、断开、缺乏和谐", "reading_upright": "一段深刻的连接正在形成。无论是爱情、友情还是合作关系，两个灵魂之间的共鸣正在发生。珍惜这段关系。", "reading_reversed": "关系中出现了一些不和谐的因素，双方可能需要更多的沟通和理解。", "keywords": ["连接", "伙伴", "和谐", "吸引", "平衡"]}, {"name": "圣杯三", "english": "Three of Cups", "symbol": "👯", "suit": "圣杯", "number": "3", "upright": "友谊、庆祝、社交、快乐聚会", "reversed": "过度放纵、社交疲劳、冲突", "reading_upright": "这是一个社交和庆祝的好时机！与朋友们聚在一起，分享快乐和欢笑。友谊和社区的力量正在支撑着你。", "reading_reversed": "你可能过于沉迷于社交活动而忽略了更重要的事情，或者人际关系中出现了一些不愉快。", "keywords": ["友谊", "庆祝", "社交", "快乐", "聚会"]}, {"name": "圣杯四", "english": "Four of Cups", "symbol": "🤔", "suit": "圣杯", "number": "4", "upright": "不满、冥想、沉思、错过机会", "reversed": "觉醒、新的机会、接受、重新连接", "reading_upright": "你可能感到一种莫名的不满或无聊，觉得生活中缺少了什么。看看你身边，可能就有一个被你忽略的机会在等待着你。", "reading_reversed": "你正在从一个沉思的状态中走出来，新的机会和可能性开始引起你的注意。", "keywords": ["不满", "沉思", "机会", "内省", "接受"]}, {"name": "圣杯五", "english": "Five of Cups", "symbol": "😢", "suit": "圣杯", "number": "5", "upright": "失去、悲伤、遗憾、失望", "reversed": "接受、走出悲伤、希望、向前看", "reading_upright": "你正在经历一段悲伤和失望的时期。失去是痛苦的，但请记住，还有杯子仍然站着。不要只看到已经失去的，也要珍惜还拥有的。", "reading_reversed": "你正在从悲伤中走出来，学会接受和释怀。前方还有新的希望在等着你。", "keywords": ["悲伤", "失去", "接受", "遗憾", "希望"]}, {"name": "圣杯六", "english": "Six of Cups", "symbol": "🌷", "suit": "圣杯", "number": "6", "upright": "童年记忆、纯真、怀旧、善意", "reversed": "放下过去、成长、现实检验", "reading_upright": "过去的美好记忆正在温暖你的心灵。你可能重新联系了童年的朋友，或者回忆起了一段纯真的时光。保持内心的那份纯真和善良。", "reading_reversed": "你可能过于沉溺于过去，需要面对现实的当下。童年虽美，但人需要成长。", "keywords": ["怀旧", "纯真", "童年", "善意", "回忆"]}, {"name": "圣杯七", "english": "Seven of Cups", "symbol": "💭", "suit": "圣杯", "number": "7", "upright": "幻想、选择、幻觉、诱惑", "reversed": "清醒、做出选择、回归现实", "reading_upright": "你面前有许多令人眼花缭乱的选择。但请注意，并非所有的选择都是真实的。辨别幻想和现实，做出对你真正有利的决定。", "reading_reversed": "你正在从幻想中回到现实，开始看清真正重要的东西。是时候做出决定了。", "keywords": ["幻想", "选择", "幻觉", "诱惑", "辨别"]}, {"name": "圣杯八", "english": "Eight of Cups", "symbol": "🚶", "suit": "圣杯", "number": "8", "upright": "离开、寻找更深的意义、放弃、精神追求", "reversed": "害怕离开、停留太久、逃避", "reading_upright": "你感到当前的局面已经无法满足你内心深处对意义的渴望。虽然离开是困难的，但你的灵魂在召唤你走向更高的地方。勇敢地转身离去吧。", "reading_reversed": "你可能知道该离开了，但因为恐惧或其他原因而迟迟不敢行动。信任你的直觉。", "keywords": ["离开", "寻找", "放弃", "意义", "勇气"]}, {"name": "圣杯九", "english": "Nine of Cups", "symbol": "😊", "suit": "圣杯", "number": "9", "upright": "满足、愿望成真、快乐、感恩", "reversed": "不满足、贪婪、欲望过多", "reading_upright": "这是一张\"愿望牌\"！你的愿望正在实现，满足感和幸福感充满你的内心。享受这份美好，同时保持感恩之心。", "reading_reversed": "你可能总是想要更多，无法感到满足。学会欣赏已经拥有的一切。", "keywords": ["满足", "愿望", "快乐", "感恩", "幸福"]}, {"name": "圣杯十", "english": "Ten of Cups", "symbol": "🌈", "suit": "圣杯", "number": "10", "upright": "幸福家庭、和谐关系、圆满、情感满足", "reversed": "家庭矛盾、关系破裂、不和谐", "reading_upright": "这是塔罗牌中最幸福的牌之一！家庭和睦，关系和谐，你正经历着情感上的极致满足。珍惜身边的人，这就是幸福的真谛。", "reading_reversed": "家庭或关系中可能存在一些不和谐的因素。用心经营你的亲密关系。", "keywords": ["幸福", "家庭", "和谐", "圆满", "满足"]}], "swords": [{"name": "宝剑Ace", "english": "Ace of Swords", "symbol": "⚔️", "suit": "宝剑", "number": "Ace", "upright": "突破、清晰、真相、力量、新思想", "reversed": "混乱、缺乏清晰、拒绝真相", "reading_upright": "一把锋利的宝剑划破迷雾，真相和清晰来到了你的面前。你的思维变得异常敏锐，可以洞察问题的核心。用你的智慧去斩断困惑吧。", "reading_reversed": "你可能被混乱和困惑所包围，无法看清真相。静下心来，理清思路。", "keywords": ["突破", "清晰", "真相", "智慧", "力量"]}, {"name": "宝剑二", "english": "Two of Swords", "symbol": "nya", "suit": "宝剑", "number": "2", "upright": "艰难选择、僵局、逃避、平衡", "reversed": "做出决定、解除僵局、信息不足", "reading_upright": "你正面对一个两难的选择，蒙着双眼不愿面对真相。逃避只是暂时的，最终你还是要做出决定。摘下眼罩，看清现实。", "reading_reversed": "你正在打破僵局，做出那个艰难的决定。虽然不安，但你终于开始行动了。", "keywords": ["选择", "僵局", "平衡", "逃避", "决定"]}, {"name": "宝剑三", "english": "Three of Swords", "symbol": "💔", "suit": "宝剑", "number": "3", "upright": "心碎、悲伤、痛苦、失落", "reversed": "愈合、释怀、走出痛苦", "reading_upright": "心碎的痛苦正在侵袭着你。无论是因为感情的结束、信任的背叛还是失望，这种痛是真实的。但请记住，心碎之后的愈合会让你变得更加强大。", "reading_reversed": "你正在从心碎中慢慢愈合，虽然还有伤痛，但你已经开始释怀。", "keywords": ["心碎", "悲伤", "痛苦", "愈合", "释放"]}, {"name": "宝剑四", "english": "Four of Swords", "symbol": "🏊", "suit": "宝剑", "number": "4", "upright": "休息、恢复、冥想、暂停", "reversed": "过度休息、恢复不够、焦虑", "reading_upright": "你需要休息了。经过一段紧张和压力之后，你的身心都需要恢复。放下武器，给自己一段安静的时光。休息是为了走更长的路。", "reading_reversed": "你可能休息了太久，不愿意重新面对现实。或者你虽然想要休息，却无法放下心中的焦虑。", "keywords": ["休息", "恢复", "冥想", "暂停", "愈合"]}, {"name": "宝剑五", "english": "Five of Swords", "symbol": "😤", "suit": "宝剑", "number": "5", "upright": "冲突、失败、 hollow victory、不道德", "reversed": "和解、放下争执、反省", "reading_upright": "你可能正在经历一场毫无意义的争斗。即使赢了也是空壳胜利，失去的比得到的多。问自己：这场战斗值得吗？", "reading_reversed": "你开始意识到争斗的无意义，选择放下和和解。这是更明智的选择。", "keywords": ["冲突", "失败", "争执", "放下", "智慧"]}, {"name": "宝剑六", "english": "Six of Swords", "symbol": "🚣", "suit": "宝剑", "number": "6", "upright": "过渡、改变、移动、离开困境", "reversed": "过渡困难、拒绝帮助、停滞", "reading_upright": "你正在渡过一段困难的水域，从困境中走向平静。虽然前路未知，但方向是明确的。接受他人的帮助，这段过渡期终将过去。", "reading_reversed": "你的过渡并不顺利，或者你拒绝接受需要帮助的事实。不要独自扛着一切。", "keywords": ["过渡", "移动", "离开", "平静", "帮助"]}, {"name": "宝剑七", "english": "Seven of Swords", "symbol": "sneak", "suit": "宝剑", "number": "7", "upright": "策略、欺骗、逃离、独立行动", "reversed": "坦白、收回策略、被揭穿", "reading_upright": "你可能需要用一些策略来达成你的目标。或者你正在试图逃离一个不舒服的处境。行动要谨慎，但也要注意不要越界。", "reading_reversed": "你的秘密或策略可能即将被揭穿。坦诚和直接可能比躲闪更有效。", "keywords": ["策略", "独立", "逃离", "谨慎", "行动"]}, {"name": "宝剑八", "english": "Eight of Swords", "symbol": "🔒", "suit": "宝剑", "number": "8", "upright": "束缚、限制、受害者心态、困境", "reversed": "自我解放、新视角、打破限制", "reading_upright": "你感觉被困住了，四周都是障碍。但仔细看——你的束缚并不是真正的锁链，而且你被蒙住了眼睛。摘下眼罩，你会发现出路一直都在。", "reading_reversed": "你正在从自我设限中解放出来，看到了以前忽略的可能性。", "keywords": ["束缚", "限制", "自由", "视角", "解放"]}, {"name": "宝剑九", "english": "Nine of Swords", "symbol": "😱", "suit": "宝剑", "number": "9", "upright": "焦虑、噩梦、担忧、过度思考", "reversed": "释放焦虑、内心平静、走出来", "reading_upright": "焦虑和担忧正在折磨着你，夜晚的噩梦让你无法安宁。但请相信，大多数你担心的事情永远不会发生。你的恐惧比现实更可怕。", "reading_reversed": "你正在从焦虑中走出来，内心重新恢复平静。噩梦即将过去。", "keywords": ["焦虑", "担忧", "噩梦", "恐惧", "释放"]}, {"name": "宝剑十", "english": "Ten of Swords", "symbol": " deepest", "suit": "宝剑", "number": "10", "upright": "最坏的结束、痛苦、跌入谷底、全新开始", "reversed": "恢复、拒绝受害者心态、缓慢愈合", "reading_upright": "这是塔罗牌中最艰难的牌之一——你跌到了谷底。但好消息是，事情已经坏到不能再坏了，从现在开始只会好转。黎明前的黑暗是最深的。", "reading_reversed": "你正在从最深的谷底慢慢爬起来。虽然过程缓慢，但你已经在好转了。", "keywords": ["结束", "谷底", "痛苦", "重生", "希望"]}], "pentacles": [{"name": "星币Ace", "english": "Ace of Pentacles", "symbol": "🪙", "suit": "星币", "number": "Ace", "upright": "新的财务机会、繁荣、安全感、新项目", "reversed": "失去机会、不安全感、糟糕的投资", "reading_upright": "一颗代表繁荣和稳定的新种子已经出现在你面前。无论是新的工作机会、投资、还是赚钱的想法，这都是一个积极的信号。抓住它！", "reading_reversed": "你可能错过了一个好的财务机会，或者对金钱感到不安全。仔细审视你的财务状况。", "keywords": ["繁荣", "机会", "稳定", "财务", "新开始"]}, {"name": "星币二", "english": "Two of Pentacles", "symbol": "🎪", "suit": "星币", "number": "2", "upright": "平衡、灵活、多任务、适应变化", "reversed": "失衡、压力、混乱、过度承诺", "reading_upright": "你正在多个领域之间平衡，如同杂耍艺人一般。这虽然忙碌，但你可以应对自如。保持灵活和幽默感，你将在变化中找到平衡。", "reading_reversed": "你可能已经不堪重负，承诺了太多事情。学会拒绝，减少你的负担。", "keywords": ["平衡", "灵活", "多任务", "适应", "变化"]}, {"name": "星币三", "english": "Three of Pentacles", "symbol": "🏗️", "suit": "星币", "number": "3", "upright": "团队合作、技能展示、建设、学习", "reversed": "缺乏协作、平庸、质量问题", "reading_upright": "团队合作正在产生出色的成果。每个人的专业技能都在贡献着价值，共同建设着宏大的项目。珍惜和重视你的合作伙伴。", "reading_reversed": "团队中可能出现了协作问题，或者工作质量没有达到预期。加强沟通。", "keywords": ["团队", "合作", "技能", "建设", "学习"]}, {"name": "星币四", "english": "Four of Pentacles", "symbol": "🛡️", "suit": "星币", "number": "4", "upright": "守财、安全感、控制、占有欲", "reversed": "慷慨、放开控制、分享、冒险", "reading_upright": "你紧紧抓住手中的资源不放，渴望安全和稳定。适度的储蓄是好的，但不要变得过于吝啬。安全和自由之间需要平衡。", "reading_reversed": "你正在学会放开对物质的执着，变得更加慷慨和开放。", "keywords": ["守财", "安全", "控制", "占有", "稳定"]}, {"name": "星币五", "english": "Five of Pentacles", "symbol": "🌨️", "suit": "星币", "number": "5", "upright": "财务困难、失去、 isolation、艰难时期", "reversed": "走出困境、获得帮助、财务恢复", "reading_upright": "你正经历一段财务或物质上的困难时期。可能感到寒冷和孤独。但即使在最黑暗的时刻，教堂的光芒依然亮着——帮助就在附近，不要羞于寻求。", "reading_reversed": "你正在从财务困境中走出来，开始看到恢复的希望。接受他人的善意。", "keywords": ["困难", "失去", "困境", "寻求帮助", "恢复"]}, {"name": "星币六", "english": "Six of Pentacles", "symbol": "🎁", "suit": "星币", "number": "6", "upright": "慷慨、慈善、给予与接受、权力平衡", "reversed": "债务、不平等、自私、贫穷心态", "reading_upright": "这是一张关于给予和接受的牌。你现在有余力去帮助他人，或者你正受到他人的慷慨帮助。无论哪种，这都是一种美好的能量流动。", "reading_reversed": "你可能正陷入债务或不平等的处境中。审视你与金钱和资源的关系。", "keywords": ["慷慨", "给予", "接受", "平衡", "帮助"]}, {"name": "星币七", "english": "Seven of Pentacles", "symbol": "🌱", "suit": "星币", "number": "7", "upright": "耐心、评估、投资回报、等待成长", "reversed": "不耐烦、缺乏进展、投入不够", "reading_upright": "你种下的种子正在缓慢但坚定地生长。现在是停下来评估一下进展的时候。你的努力终将得到回报，只是还需要更多的耐心。", "reading_reversed": "你可能对进展缓慢感到沮丧，考虑是否要放弃。也许你需要换一种方法，或者只是需要更多耐心。", "keywords": ["耐心", "评估", "等待", "成长", "投资"]}, {"name": "星币八", "english": "Eight of Pentacles", "symbol": "🔨", "suit": "星币", "number": "8", "upright": "勤奋、精进、工匠精神、专注", "reversed": "缺乏动力、工作质量差、完美主义", "reading_upright": "你正在投入大量的时间和精力来精进你的技能。像工匠一样专注和用心，你的努力正在一点一滴地积累出精湛的技艺。保持专注， excellence 终将到来。", "reading_reversed": "你可能缺乏动力或者心不在焉，工作质量在下滑。找回你的专注和热情。", "keywords": ["勤奋", "精进", "专注", "技能", "工匠"]}, {"name": "星币九", "english": "Nine of Pentacles", "symbol": "👸", "suit": "星币", "number": "9", "upright": "丰盛、独立、奢华、自给自足", "reversed": "虚假的丰盛、依赖、缺乏安全感", "reading_upright": "你通过自己的努力和智慧，创造了属于自己的丰盛生活。独立而优雅，你享受着劳动的果实。这是一张代表自给自足和优雅生活的牌。", "reading_reversed": "你可能过度依赖外在的标签来定义自己的价值，或者在追求物质享受中迷失了方向。", "keywords": ["丰盛", "独立", "优雅", "自足", "享受"]}, {"name": "星币十", "english": "Ten of Pentacles", "symbol": "own", "suit": "星币", "number": "10", "upright": "财富传承、家庭繁荣、长期成功、富足", "reversed": "财务不稳定、家庭遗产问题、失去财富", "reading_upright": "这是物质层面的极致圆满。家族的财富和智慧得到了传承，长期的规划和努力终于结出了丰硕的果实。享受这份来之不易的富足和安全感。", "reading_reversed": "你可能正面临一些财务或家庭遗产方面的问题。审视你的长期财务规划。", "keywords": ["财富", "传承", "家庭", "繁荣", "圆满"]}]}};
